#include<bits/stdc++.h>
using namespace std;
long long n;
char s[500010];
long long dp[500010];
const long long mod=1e9+7;
struct szsz
{
    long long s[500010];
    long long lowbit(long long x)
    {
        return x&-x;
    }
    void update(long long x,long long k)
    {
        for(long long i=x;i<=n;i+=lowbit(i))
        {
            s[i]+=k;
            s[i]%=mod;
        }
    }
    long long sum(long long x)
    {
        long long ans=0;
        for(long long i=x;i;i-=lowbit(i))
        {
            ans+=s[i];
            ans%=mod;
        }
        return ans;
    }
}t[2];
vector<long long> v[500010];
int main()
{
    long long lastr=0,lb=1;
    scanf("%lld%s",&n,s+1);
    dp[0]=1;
    for(long long i=1;i<=n;i++)
    {
        if(s[i]=='X')
        {
            dp[i]=dp[i-1];
        }
        else if(s[i]=='R')
        {
            lastr=i;
        }
        else
        {
            while(lb<=i)
            {
                if(i*2-lb<=n)
                {
                    v[i*2-lb].push_back(lb);
                }
                lb++;
            }
        }
        for(long long j:v[i])
        {
            t[j&1].update(j,-dp[j-1]);
        }
        long long l=max(1ll,lastr*2-i+1);
        dp[i]+=((t[((i&1)^1)].sum(i)-t[((i&1)^1)].sum(l-1))%mod+mod)%mod;
        dp[i]%=mod;
        t[i&1].update(i,dp[i-1]);
    }
    printf("%lld\n",dp[n]);
    return 0;
}
